import{c as e,Q as t,j as a,m as r}from"./chunks/framework.iD28w_5a.js";const c=JSON.parse('{"title":"027-fs-vfs-3 · VFS 虚拟文件系统","description":"","frontmatter":{"title":"027-fs-vfs-3 · VFS 虚拟文件系统"},"headers":[],"relativePath":"hands-on/027-fs-vfs-3.md","filePath":"hands-on/027-fs-vfs-3.md","lastUpdated":1779686691000}'),i={name:"hands-on/027-fs-vfs-3.md"};function o(n,s,d,p,l,h){return t(),a("div",null,[...s[0]||(s[0]=[r(`<h1 id="_027-3-hands-on-ramdisk-vfs-适配与系统调用-—-让-open-read-write-跑起来" tabindex="-1">027-3 Hands-on: Ramdisk VFS 适配与系统调用 — 让 open/read/write 跑起来 <a class="header-anchor" href="#_027-3-hands-on-ramdisk-vfs-适配与系统调用-—-让-open-read-write-跑起来" aria-label="Permalink to &quot;027-3 Hands-on: Ramdisk VFS 适配与系统调用 — 让 open/read/write 跑起来&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>前两章我们搭好了数据结构（Inode/File/FDTable）和挂载点表（vfs_mount/vfs_resolve），但这一切都还只是&quot;框架&quot;——没有任何代码真正地把 open 系统调用和 VFS 串联起来。这一章我们就来做这件事：让 Ramdisk 继承 FileSystem 抽象基类、实现 mount() 和 lookup()、提供三组 InodeOps 函数指针表（读归档数据、写返回错误、遍历目录项），然后新增 sys_open/sys_close/sys_getdents 三个系统调用，同时改造 sys_read/sys_write 让它们在 fd != 0/1 时走 VFS 路径。</p><p>完成本章后，内核的 open/read/write/close 全链路就打通了——从用户态的 libc wrapper 到 syscall dispatch，再到 VFS resolve、FileSystem lookup、InodeOps 回调，最终到 Ramdisk 的数据拷贝。在 QEMU 里你应该能看到 shell 的 cat 命令打印出 initrd 里文件的内容。</p><p>知识前置：027-1（VFS 数据结构）、027-2（挂载点表）、026（Ramdisk 解析）。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="ramdisk-适配-—-从-解析器-到-文件系统" tabindex="-1">Ramdisk 适配 — 从&quot;解析器&quot;到&quot;文件系统&quot; <a class="header-anchor" href="#ramdisk-适配-—-从-解析器-到-文件系统" aria-label="Permalink to &quot;Ramdisk 适配 — 从&quot;解析器&quot;到&quot;文件系统&quot;&quot;">​</a></h3><p>在 026 里，Ramdisk::mount() 只是遍历 ustar 归档打印文件名，返回条目数量。现在我们需要把它升级成一个真正的文件系统后端：mount() 要构建一个内部条目表，每个条目包含文件名、数据指针、大小，以及一个预分配的 Inode。lookup() 根据文件名在条目表里做线性搜索。这种设计简单粗暴——线性搜索 O(n) 在条目数少的时候完全够用，我们的 RAMDISK_MAX_ENTRIES 只有 64。</p><p>关键变化是 RamdiskEntry 结构：之前 name 字段是一个 const char*（指向 ustar header 里的 name），现在改成了 char 数组（拷贝出来，不依赖 header 的生命周期），并且内嵌了一个 Inode 对象。这样每个文件条目都自带自己的 inode，不需要额外分配内存。同时新增了 RamdiskDirContext 结构来辅助 readdir——它保存条目表指针和条目数量，让 readdir 函数不需要直接访问 Ramdisk 的私有成员。Ramdisk 提供两个静态 InodeOps 实例——ramdisk_file_ops（普通文件操作）和 ramdisk_dir_ops（目录操作），每个实例的函数指针指向对应的实现函数，不支持的操作保持 nullptr。</p><h3 id="地址校验-—-从-user-addr-max-到-canonical-address" tabindex="-1">地址校验 — 从 USER_ADDR_MAX 到 Canonical Address <a class="header-anchor" href="#地址校验-—-从-user-addr-max-到-canonical-address" aria-label="Permalink to &quot;地址校验 — 从 USER_ADDR_MAX 到 Canonical Address&quot;">​</a></h3><p>之前的 sys_read/sys_write 用一个简单的 <code>buf_virt &gt;= 0x800000000000</code> 来拒绝内核地址。这个检查有问题：x86_64 的规范地址空间不是在某个固定值一刀切的——48 位线性地址空间的高半部分（内核空间）地址是 0xFFFF800000000000 到 0xFFFFFFFFFFFFFFFF，而不是从 0x800000000000 开始。</p><p>x86_64 的 canonical address 规则是：bit 47 决定了 bits 48-63 应该全是 0 还是全是 1。如果 bit 47 是 0，那 bits 48-63 必须全为 0；如果 bit 47 是 1，那 bits 48-63 必须全为 1。我们用这个规则替换了简单的上限检查，同时把 nullptr（地址 0）单独拒绝。</p><h3 id="系统调用分发更新" tabindex="-1">系统调用分发更新 <a class="header-anchor" href="#系统调用分发更新" aria-label="Permalink to &quot;系统调用分发更新&quot;">​</a></h3><p>新增的三个系统调用号：SYS_open=2、SYS_close=3、SYS_getdents=78。open 的流程是 vfs_resolve 找后端、fs-&gt;lookup 找 inode、FDTable::alloc 分配 fd。close 就是 FDTable::close。getdents 比较特殊——它通过 fd 找到 File，再用 file-&gt;inode-&gt;ops-&gt;readdir 读取目录项，用 file-&gt;offset 当目录项索引（每次成功后 offset++）。这个设计虽然不太 POSIX（真正的 getdents 返回的是 linux_dirent 结构体），但对我们的简单 shell 来说够用了。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-让-ramdisk-继承-filesystem" tabindex="-1">Step 1: 让 Ramdisk 继承 FileSystem <a class="header-anchor" href="#step-1-让-ramdisk-继承-filesystem" aria-label="Permalink to &quot;Step 1: 让 Ramdisk 继承 FileSystem&quot;">​</a></h3><p><strong>目标</strong>: 修改 <code>kernel/fs/ramdisk.hpp</code>，让 Ramdisk 类继承 FileSystem 抽象基类。</p><p><strong>设计思路</strong>: 在类声明中加上 <code>: public FileSystem</code>，把 mount() 的返回类型从 uint32_t 改为 bool，新增 <code>Inode* lookup(const char* path) override</code> 方法。新增私有成员：entries_ 数组（RamdiskEntry[64]，预分配条目表）、entry_count_（条目数量）、root_inode_（根目录 inode，用于 readdir）、root_ctx_（RamdiskDirContext，用于 readdir）。Ramdisk 提供两个静态 InodeOps 实例（ramdisk_file_ops 和 ramdisk_dir_ops），每个实例的函数指针指向 ramdisk.cpp 匿名命名空间里的实现函数。</p><p><strong>实现约束</strong>: RAMDISK_MAX_ENTRIES = 64，RAMDISK_NAME_MAX = 100。RamdiskEntry 的 name 字段从 const char* 改为 char[100]（拷贝文件名，不依赖 ustar header 的生命周期），内嵌 Inode inode 字段。</p><p><strong>踩坑预警</strong>: RamdiskEntry 的内存布局变了——之前只有三个指针字段（name/size/data），现在加了 Inode（约 40 字节）和 name 数组（100 字节），每个条目变成了约 160 字节。entries_ 是 64 个条目的数组，总共约 10KB。对于内核栈来说太大了，所以 Ramdisk 对象必须分配在堆上或作为 static 变量（我们在 main.cpp 中用了 static）。</p><p><strong>验证</strong>: 编译通过。</p><h3 id="step-2-实现-ramdisk-的-inodeops" tabindex="-1">Step 2: 实现 Ramdisk 的 InodeOps <a class="header-anchor" href="#step-2-实现-ramdisk-的-inodeops" aria-label="Permalink to &quot;Step 2: 实现 Ramdisk 的 InodeOps&quot;">​</a></h3><p><strong>目标</strong>: 在 <code>kernel/fs/ramdisk.cpp</code> 中实现 ramdisk_file_ops 和 ramdisk_dir_ops 两个静态 InodeOps 实例。</p><p><strong>设计思路</strong>: ramdisk_file_ops 设置 read 函数指针：从 inode-&gt;fs_private 拿到 RamdiskEntry 指针，从 entry-&gt;data + offset 拷贝 min(count, entry-&gt;size - offset) 字节到用户缓冲区。write 函数指针设为 nullptr（只读文件系统）。ramdisk_dir_ops 设置 readdir 函数指针：从 inode-&gt;fs_private 拿到 RamdiskDirContext，index=0 返回 &quot;.&quot;，index=1 返回 &quot;..&quot;，index&gt;=2 返回 entries[index-2].name。两个 ops 实例都放在匿名命名空间里，避免符号泄漏。</p><p><strong>实现约束</strong>: ramdisk_read 需要检查 offset &gt;= size 的情况——此时返回 0（EOF）。ramdisk_readdir 的 index 参数直接用 uint64_t，不做任何转换。两个 InodeOps 实例放在匿名命名空间里，作为静态全局变量直接定义（<code>static InodeOps ramdisk_file_ops = { .read = ramdisk_read, .write = nullptr, ... }</code>），不需要 new 分配。</p><p><strong>踩坑预警</strong>: ramdisk_read 的 buf 参数是 void*（内核地址），在 syscall handler 中已经由 sys_read 从用户态虚拟地址转换过来了。但注意，我们现在直接把用户态地址传给 InodeOps——这在 kernel test 中工作正常（因为测试用的地址就是内核地址），但在真正的用户态 syscall 中，这个地址是用户态虚拟地址，需要确保页表映射正确。目前的实现依赖 QEMU 的 identity mapping，暂无问题。</p><p><strong>验证</strong>: 编译通过。运行 kernel 测试中的 test_ramdisk 部分——应该有新增的 lookup 和 InodeOps 测试通过。</p><h3 id="step-3-改造-ramdisk-mount-和实现-lookup" tabindex="-1">Step 3: 改造 Ramdisk::mount() 和实现 lookup() <a class="header-anchor" href="#step-3-改造-ramdisk-mount-和实现-lookup" aria-label="Permalink to &quot;Step 3: 改造 Ramdisk::mount() 和实现 lookup()&quot;">​</a></h3><p><strong>目标</strong>: 更新 mount() 以构建条目表，新增 lookup() 方法。</p><p><strong>设计思路</strong>: mount() 的主循环不变（遍历 ustar 条目），但不再是只打印文件名——而是把每个文件的信息填入 entries_ 数组，同时设置对应的 Inode（ino=序号、size=文件大小、type=Regular、ops=&amp;ramdisk_file_ops、fs_private=&amp;entry）。循环结束后设置 root_inode_ 和 root_ctx_。lookup() 处理三种情况：空路径或 &quot;/&quot; 返回根目录 inode；否则跳过前导 &#39;/&#39; 后线性搜索条目表。</p><p><strong>实现约束</strong>: mount() 最后返回 entry_count_ &gt; 0。lookup() 对 nullptr 路径返回 nullptr。root_inode_ 的 type 设为 Directory，ops 指向 ramdisk_dir_ops，fs_private 设为 &amp;root_ctx_。</p><p><strong>验证</strong>: 编译并运行 kernel 测试。test_ramdisk 部分应该有 7 个 lookup 测试和 5 个 InodeOps 测试通过。</p><h3 id="step-4-实现-sys-open" tabindex="-1">Step 4: 实现 sys_open <a class="header-anchor" href="#step-4-实现-sys-open" aria-label="Permalink to &quot;Step 4: 实现 sys_open&quot;">​</a></h3><p><strong>目标</strong>: 创建 <code>kernel/syscall/sys_open.cpp</code> 和 <code>sys_open.hpp</code>。</p><p><strong>设计思路</strong>: 四步流程——第一步调用 resolve_user_path() 做路径解析（内部包含 canonical address 校验和 cwd 感知的路径规范化）；第二步调用 vfs_resolve 找到对应的 FileSystem 后端；第三步调用 fs-&gt;lookup(rel_path) 找到 Inode；第四步把 flags 映射到 OpenFlags 后调用 current_fd_table().alloc() 分配 fd。</p><p><strong>实现约束</strong>: resolve_user_path() 封装在 kernel/syscall/path_util.hpp 中，内部做 canonical address 检查（提取 bit47，如果 bit47=0 则 upper 必须为 0，如果 bit47=1 则 upper 必须为 0xFFFF）并将路径解析为绝对路径。flags 映射：0→RDONLY, 1→WRONLY, 2→RDWR，其他默认 RDONLY。使用 current_fd_table() 而非 g_global_fd_table()，支持 per-process FDTable。</p><p><strong>踩坑预警</strong>: path 参数是用户态传上来的虚拟地址，sys_open 直接 reinterpret_cast 为 const char*。这个地址在用户态页表中必须有效——如果用户传了一个无效地址（比如已经 free 掉的内存），内核会页错误。在当前的简化实现中，我们先不处理这种情况（以后加 page fault handler 时再完善）。</p><p><strong>验证</strong>: 编译通过。</p><h3 id="step-5-实现-sys-close" tabindex="-1">Step 5: 实现 sys_close <a class="header-anchor" href="#step-5-实现-sys-close" aria-label="Permalink to &quot;Step 5: 实现 sys_close&quot;">​</a></h3><p><strong>目标</strong>: 创建 <code>kernel/syscall/sys_close.cpp</code> 和 <code>sys_close.hpp</code>。</p><p><strong>设计思路</strong>: 极其简单——调用 current_fd_table().close(fd)，把返回值转成 int64_t 返回。所有边界检查和双重关闭检查都在 FDTable::close 里做。</p><p><strong>验证</strong>: 编译通过。</p><h3 id="step-6-实现-sys-getdents" tabindex="-1">Step 6: 实现 sys_getdents <a class="header-anchor" href="#step-6-实现-sys-getdents" aria-label="Permalink to &quot;Step 6: 实现 sys_getdents&quot;">​</a></h3><p><strong>目标</strong>: 创建 <code>kernel/syscall/sys_getdents.cpp</code> 和 <code>sys_getdents.hpp</code>。</p><p><strong>设计思路</strong>: 先做 canonical address 校验，然后通过 current_fd_table() 拿到 File，检查 ops-&gt;readdir 是否存在。在 offset_lock_ 保护下调用 readdir(inode, file-&gt;offset, buf, count)，成功（返回 1）时 offset++ 并返回名称长度，目录结束（返回 0）时返回 0，错误（返回 -1）时返回 -1。</p><p><strong>实现约束</strong>: buf_virt 参数是用户态虚拟地址，直接 reinterpret_cast 为 char* 后传给 readdir。file-&gt;offset 在这里被复用为目录项索引——这是一个巧妙但有点 hacky 的设计，offset 本来是文件读写偏移量，对于目录 fd 来说它变成了目录项的 0-based 索引。</p><p><strong>验证</strong>: 编译通过。</p><h3 id="step-7-更新-sys-read-和-sys-write-—-vfs-路径" tabindex="-1">Step 7: 更新 sys_read 和 sys_write — VFS 路径 <a class="header-anchor" href="#step-7-更新-sys-read-和-sys-write-—-vfs-路径" aria-label="Permalink to &quot;Step 7: 更新 sys_read 和 sys_write — VFS 路径&quot;">​</a></h3><p><strong>目标</strong>: 修改现有的 <code>kernel/syscall/sys_read.cpp</code> 和 <code>sys_write.cpp</code>。</p><p><strong>设计思路</strong>: sys_read 和 sys_write 都采用&quot;VFS 优先&quot;策略——先查 FDTable 看这个 fd 是否有对应的 File，如果有就走 VFS 路径；如果没有，再检查 fd=0（键盘）或 fd=1（kprintf）的 legacy 路径。这种设计比简单的 fd==0/fd!=0 分支更灵活——它允许 fd=0 被重新分配为 pipe 或其他 VFS 后端。</p><p><strong>实现约束</strong>: sys_read 的 VFS 路径：先通过 current_fd_table().get(fd) 获取 File，检查三层非空（file/inode/ops），然后在 offset_lock_ 保护下调用 ops-&gt;read(file-&gt;inode, file-&gt;offset, buf, count)，返回值 &gt; 0 时 file-&gt;offset += result。sys_write 同理。</p><p><strong>踩坑预警</strong>: 别忘了在 sys_read 里保留 fd=0 的键盘路径——否则 shell 的命令输入就断了！在 sys_write 里保留 fd=1 的 kprintf 路径——否则所有 printf 输出都消失了。</p><p><strong>验证</strong>: 编译并运行全量 kernel 测试。</p><h3 id="step-8-注册新系统调用" tabindex="-1">Step 8: 注册新系统调用 <a class="header-anchor" href="#step-8-注册新系统调用" aria-label="Permalink to &quot;Step 8: 注册新系统调用&quot;">​</a></h3><p><strong>目标</strong>: 修改 <code>kernel/arch/x86_64/syscall.cpp</code> 和 <code>kernel/syscall/syscall_nums.hpp</code>。</p><p><strong>设计思路</strong>: 在 syscall_nums.hpp 中新增 SYS_open=2、SYS_close=3、SYS_getdents=78。在 register_builtin_handlers() 中注册这三个新 handler。</p><p><strong>验证</strong>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel_test</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-system-x86_64</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -serial</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stdio</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -kernel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel_test.bin</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;&amp;1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;(PASS|FAIL|VFS)&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test_host</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> big_kernel_test</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Host 测试（test_fd_table + test_vfs_mount）+ kernel 测试（test_vfs_syscall，23 个用例覆盖 open/close/read/write/getdents 全链路）应该全部通过。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>sys_open 返回 -1 但路径确实存在</strong>: 检查 vfs_resolve 的输出——如果 rel_path 不对（比如多了个前导 &#39;/&#39; 或少了字符），lookup 自然找不到。加个 kprintf 打印 resolve 后的 rel_path 看看。</p><p><strong>sys_read 返回 -1</strong>: 最可能的原因是 ops 或 ops-&gt;read 为 nullptr——检查 inode 的 ops 指针是否正确设置了。另一个可能是 buf 地址不合法（canonical address 检查不过）。</p><p><strong>getdents 只返回 &quot;.&quot; 和 &quot;..&quot; 但没有文件</strong>: 检查 root_ctx_ 的 entries 和 count 是否正确设置——如果 mount() 里没有正确设置 root_ctx_，readdir 拿到的 count 就是 0，自然读不到文件。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>要点</th></tr></thead><tbody><tr><td>Ramdisk 继承 FileSystem</td><td>mount() 返回 bool，新增 lookup() 线性搜索，静态 ops 实例</td></tr><tr><td>InodeOps</td><td>ramdisk_file_ops（read 拷贝数据/write 为 nullptr）、ramdisk_dir_ops（readdir 返回目录项）</td></tr><tr><td>sys_open</td><td>resolve_user_path → vfs_resolve → lookup → current_fd_table().alloc</td></tr><tr><td>sys_close</td><td>直接调用 current_fd_table().close(fd)</td></tr><tr><td>sys_getdents</td><td>fd → File → Inode → ops-&gt;readdir，offset 当索引用</td></tr><tr><td>sys_read/write 更新</td><td>fd=0/1 保留旧逻辑，其他 fd 走 VFS</td></tr><tr><td>canonical address</td><td>bit47 决定 bits 48-63 应全为 0 或全为 1</td></tr></tbody></table>`,67)])])}const _=e(i,[["render",o]]);export{c as __pageData,_ as default};
